const jiraAbiertos  = $('Jira: Bugs Abiertos').first().json;
const jiraResueltos = $('Jira: Bugs Resueltos').first().json;
const githubData    = $('GitHub: Pipeline Runs').first().json;

const issues     = jiraAbiertos.issues  || [];
const totalOpen  = jiraAbiertos.total   || issues.length;
const totalFixed = jiraResueltos.total  || (jiraResueltos.issues || []).length;

const criticos = issues.filter(i => {
  const p = i.fields?.priority?.name || '';
  return p === 'Critical' || p === 'Highest' || p === 'High';
}).length;
const medios = issues.filter(i => i.fields?.priority?.name === 'Medium').length;

const runs     = githubData.workflow_runs || [];
const recent10 = runs.slice(0, 10);
const runsOk   = recent10.filter(r => r.conclusion === 'success').length;
const passRate = recent10.length > 0 ? Math.round(runsOk / recent10.length * 100) : 0;
const lastRun  = recent10[0] || {};

// Jobs del ultimo run (desde nodo HTTP separado)
let jobsTotal  = 0;
let jobsOk     = 0;
let failedSpec = '';

const jobsData = $input.first().json;
const matrixJobs = (jobsData.jobs || []).filter(j =>
  j.name.includes('Tests Criticos') || j.name.includes('Portal Pacientes')
);
jobsTotal = matrixJobs.length > 0 ? matrixJobs.length : (jobsData.jobs || []).length;
jobsOk    = matrixJobs.length > 0
  ? matrixJobs.filter(j => j.conclusion === 'success').length
  : (jobsData.jobs || []).filter(j => j.conclusion === 'success').length;

const failedJob = (jobsData.jobs || []).find(j => j.conclusion === 'failure');
if (failedJob) {
  const match = failedJob.name.match(/\(([^)]+)\)/);
  failedSpec = match ? match[1].replace('cypress/e2e/bupa/', '') : failedJob.name;
}

const lastStatus = lastRun.conclusion === 'success' ? 'PASSED'
                 : lastRun.conclusion === 'failure'  ? 'FAILED' : 'Running';

const ahora      = new Date();
const hora       = ahora.toLocaleTimeString('es-CL', { timeZone:'America/Santiago', hour:'2-digit', minute:'2-digit' });
const dd         = String(ahora.getDate()).padStart(2,'0');
const mm         = String(ahora.getMonth()+1).padStart(2,'0');
const yyyy       = ahora.getFullYear();
const fechaCorta = `${dd}-${mm}-${yyyy}`;
const fechaLarga = ahora.toLocaleDateString('es-CL', { timeZone:'America/Santiago', weekday:'long', year:'numeric', month:'long', day:'numeric' });

const prioColor = { Critical:'#C62828', Highest:'#C62828', High:'#E65100', Medium:'#F9A825', Low:'#388E3C', Lowest:'#388E3C' };
const prioEmoji = { Critical:'🔴', Highest:'🔴', High:'🟠', Medium:'🟡', Low:'🟢', Lowest:'🟢' };
const typeEmoji = { Bug:'🐛', Task:'📋', Story:'📖', Epic:'⚡' };

const rowsIssues = issues.slice(0, 8).map(i => {
  const prio  = i.fields?.priority?.name || 'Medium';
  const color = prioColor[prio] || '#757575';
  const emoji = prioEmoji[prio] || '⚪';
  const tipo  = typeEmoji[i.fields?.issuetype?.name] || '📌';
  const key   = i.key || '';
  const sum   = (i.fields?.summary || '').substring(0, 55);
  const stat  = i.fields?.status?.name || '';
  const url   = `https://qaprocess1.atlassian.net/browse/${key}`;
  return `<tr style="border-bottom:1px solid #E3F2FD">
    <td style="padding:8px 10px"><a href="${url}" style="color:#1976D2;font-weight:bold;text-decoration:none">${key}</a></td>
    <td style="padding:8px 10px;font-size:13px">${tipo} ${sum}</td>
    <td style="padding:8px 10px;text-align:center"><span style="background:${color}20;color:${color};padding:2px 8px;border-radius:10px;font-size:11px;font-weight:bold">${emoji} ${prio}</span></td>
    <td style="padding:8px 10px;text-align:center;font-size:12px;color:#546E7A">${stat}</td>
  </tr>`;
}).join('');

const rowsRuns = recent10.slice(0, 5).map(r => {
  const ok    = r.conclusion === 'success';
  const color = ok ? '#2E7D32' : r.conclusion === 'failure' ? '#C62828' : '#F57F17';
  const icon  = ok ? '✅' : r.conclusion === 'failure' ? '❌' : '⏳';
  const d     = new Date(r.created_at);
  const fRun  = `${String(d.getDate()).padStart(2,'0')}-${String(d.getMonth()+1).padStart(2,'0')}-${d.getFullYear()}`;
  const spec  = (r.id === lastRun.id && failedSpec) ? `<br><span style="font-size:10px;color:#C62828">↳ ${failedSpec}</span>` : '';
  return `<tr style="border-bottom:1px solid #E3F2FD">
    <td style="padding:7px 10px"><span style="color:${color};font-weight:bold">${icon} ${(r.conclusion||'running').toUpperCase()}</span>${spec}</td>
    <td style="padding:7px 10px;font-size:12px;color:#1976D2">${(r.head_branch||'').substring(0,20)}</td>
    <td style="padding:7px 10px;font-size:12px;color:#546E7A">${fRun}</td>
    <td style="padding:7px 10px;font-size:12px;color:#546E7A">${r.actor?.login||'N/A'}</td>
  </tr>`;
}).join('');

const failedMsg = failedSpec ? `⚠️ Último fallo: <b>${failedSpec}</b><br>` : '';
const jobsLabel = jobsTotal > 0 ? `${jobsOk}/${jobsTotal}` : `${runsOk}/${recent10.length}`;

const htmlEmail = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#F0F4F8;font-family:Arial,sans-serif">
<div style="max-width:700px;margin:20px auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,0.1)">
  <div style="background:linear-gradient(135deg,#0D47A1 0%,#1976D2 100%);padding:28px 32px">
    <div style="color:#64B5F6;font-size:11px;font-weight:bold;letter-spacing:2px;text-transform:uppercase">QUALITY ASSURANCE</div>
    <div style="color:white;font-size:22px;font-weight:bold;margin-top:4px">Dashboard Semanal QA</div>
    <div style="color:#90CAF9;font-size:12px;margin-top:3px">Jira + GitHub Actions — BUPA Portal Pacientes</div>
    <div style="color:#BBDEFB;font-size:11px;margin-top:12px;border-top:1px solid rgba(255,255,255,0.2);padding-top:10px">
      📅 ${fechaLarga.charAt(0).toUpperCase()+fechaLarga.slice(1)}  •  🕐 ${hora} hrs  •  QA Lead: Jaime Quiñelen
    </div>
  </div>
  <div style="padding:24px 32px 8px">
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr 1fr;gap:10px">
      <div style="background:#FFF3E0;border-radius:8px;padding:12px;border-left:4px solid #E65100;text-align:center">
        <div style="font-size:26px;font-weight:bold;color:#E65100">${totalOpen}</div>
        <div style="font-size:10px;color:#BF360C;font-weight:bold;margin-top:2px">ABIERTOS</div>
      </div>
      <div style="background:#FFEBEE;border-radius:8px;padding:12px;border-left:4px solid #C62828;text-align:center">
        <div style="font-size:26px;font-weight:bold;color:#C62828">${criticos}</div>
        <div style="font-size:10px;color:#B71C1C;font-weight:bold;margin-top:2px">CRÍTICOS</div>
      </div>
      <div style="background:#E8F5E9;border-radius:8px;padding:12px;border-left:4px solid #2E7D32;text-align:center">
        <div style="font-size:26px;font-weight:bold;color:#2E7D32">${totalFixed}</div>
        <div style="font-size:10px;color:#1B5E20;font-weight:bold;margin-top:2px">RESUELTOS</div>
      </div>
      <div style="background:#E3F2FD;border-radius:8px;padding:12px;border-left:4px solid #1976D2;text-align:center">
        <div style="font-size:26px;font-weight:bold;color:#1976D2">${runsOk}/${recent10.length}</div>
        <div style="font-size:10px;color:#0D47A1;font-weight:bold;margin-top:2px">RUNS OK</div>
        <div style="font-size:9px;color:#546E7A;margin-top:1px">histórico</div>
      </div>
      <div style="background:#EDE7F6;border-radius:8px;padding:12px;border-left:4px solid #6A1B9A;text-align:center">
        <div style="font-size:26px;font-weight:bold;color:#6A1B9A">${jobsLabel}</div>
        <div style="font-size:10px;color:#4A148C;font-weight:bold;margin-top:2px">JOBS OK</div>
        <div style="font-size:9px;color:#546E7A;margin-top:1px">último run</div>
      </div>
    </div>
  </div>
  <div style="padding:20px 32px">
    <div style="font-size:14px;font-weight:bold;color:#0D47A1;margin-bottom:10px">📋 Abiertos</div>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead><tr style="background:#0D47A1">
        <th style="padding:9px 10px;text-align:left;color:white;font-size:11px;width:80px">ID</th>
        <th style="padding:9px 10px;text-align:left;color:white;font-size:11px">Descripción</th>
        <th style="padding:9px 10px;text-align:center;color:white;font-size:11px;width:100px">Prioridad</th>
        <th style="padding:9px 10px;text-align:center;color:white;font-size:11px;width:90px">Estado</th>
      </tr></thead>
      <tbody>${rowsIssues||'<tr><td colspan="4" style="padding:12px;text-align:center;color:#9E9E9E">Sin issues abiertos</td></tr>'}</tbody>
    </table>
  </div>
  <div style="padding:4px 32px 20px">
    <div style="font-size:14px;font-weight:bold;color:#0D47A1;margin-bottom:10px">⚙️ Pipeline — últimos runs</div>
    <table style="width:100%;border-collapse:collapse;font-size:13px">
      <thead><tr style="background:#1565C0">
        <th style="padding:9px 10px;text-align:left;color:white;font-size:11px;width:160px">Resultado</th>
        <th style="padding:9px 10px;text-align:left;color:white;font-size:11px">Branch</th>
        <th style="padding:9px 10px;text-align:center;color:white;font-size:11px;width:110px">Fecha</th>
        <th style="padding:9px 10px;text-align:center;color:white;font-size:11px;width:90px">Actor</th>
      </tr></thead>
      <tbody>${rowsRuns||'<tr><td colspan="4" style="padding:12px;text-align:center;color:#9E9E9E">Sin datos</td></tr>'}</tbody>
    </table>
  </div>
  <div style="margin:0 32px 20px;background:#E3F2FD;border-radius:8px;padding:16px;border-left:4px solid #1976D2">
    <div style="font-size:12px;font-weight:bold;color:#0D47A1;margin-bottom:8px">📊 Resumen Ejecutivo</div>
    <div style="font-size:12px;color:#1A237E;line-height:1.7">
      ${failedMsg}
      • Pipeline: <b>${runsOk} de ${recent10.length} runs OK</b> (${passRate}%) — Último: ${lastStatus}<br>
      • Jobs último run: <b>${jobsOk}/${jobsTotal} exitosos</b>${failedSpec ? ` — fallo: <b>${failedSpec}</b>` : ''}<br>
      • Issues: <b>${totalOpen} abiertos</b> (${criticos} críticos) — <b>${totalFixed} resueltos</b>
    </div>
  </div>
  <div style="background:#0D47A1;padding:16px 32px;text-align:center">
    <div style="color:#90CAF9;font-size:11px">Generado por <b style="color:white">WF-1.10 Dashboard QA</b> — n8n  •  BUPA Chile</div>
    <div style="color:#64B5F6;font-size:10px;margin-top:4px">QA Lead: Jaime Quiñelen  •  ${fechaCorta}  •  ${hora} hrs</div>
  </div>
</div></body></html>`;

const asunto = `📊 [WF-1.10] Dashboard Semanal QA (4PM) — ${passRate}% Pass Rate — ${criticos>0?'🔴 '+criticos+' críticos':'✅ sin críticos'} — ${fechaCorta}`;
return [{ json: { htmlEmail, asunto } }];
